// Merge results from 3 parallel HTTP calls + integration details
// Items arrive in order: flows response, errors response, connections response
// Integration data came from Fetch Integration node before branching

// Gather all inputs
const items = $input.all();

// Node outputs are collected by the merge node in the order connections arrive
// We identify them by structure
let flowsData, errorsData, connectionsData;
for (const item of items) {
  const d = item.json;
  // Flows: array with items having 'disabled' field
  if (Array.isArray(d) && d.length > 0 && 'disabled' in d[0]) {
    flowsData = d;
  }
  // Errors: array with items having 'numError' field, OR wrapper object
  else if (Array.isArray(d) && d.length > 0 && 'numError' in d[0]) {
    errorsData = d;
  }
  // Connections: array with items having 'type' and 'offline' fields
  else if (Array.isArray(d) && d.length > 0 && 'type' in d[0] && 'offline' in d[0]) {
    connectionsData = d;
  }
  // Connections: could also be empty array
  else if (Array.isArray(d) && d.length === 0 && !flowsData) {
    // ambiguous empty — skip
  }
  // Errors wrapper object
  else if (!Array.isArray(d) && Array.isArray(d.errors)) {
    errorsData = d.errors;
  }
}

flowsData = flowsData || [];
errorsData = errorsData || [];
connectionsData = connectionsData || [];

// Get integration detail from Fetch Integration node
const integration = $('Fetch Integration').first().json;

// Slim integration fields
const integrationSlim = {
  _id: integration._id,
  name: integration.name,
  description: integration.description,
  sandbox: integration.sandbox,
  lastModified: integration.lastModified,
  createdAt: integration.createdAt,
};

// Slim flows
const FLOW_KEEP = ['_id', 'name', 'disabled', 'lastModified', 'lastExecutedAt', 'free'];
const flows = flowsData.map(f => {
  const out = {};
  for (const k of FLOW_KEEP) if (k in f) out[k] = f[k];
  return out;
});
const activeFlows = flows.filter(f => !f.disabled);
const disabledFlows = flows.filter(f => f.disabled);

// Slim connections
const CONN_KEEP = ['_id', 'name', 'type', 'offline', 'sandbox'];
const connections = connectionsData.map(c => {
  const out = {};
  for (const k of CONN_KEEP) if (k in c) out[k] = c[k];
  return out;
});

// Compute total errors
const totalErrors = errorsData.reduce((sum, e) => sum + (e.numError || 0), 0);

const result = {
  integration: integrationSlim,
  summary: {
    total_flows: flows.length,
    active_flows: activeFlows.length,
    disabled_flows: disabledFlows.length,
    total_errors: totalErrors,
    total_connections: connections.length,
    offline_connections: connections.filter(c => c.offline).length,
  },
  flows,
  connections,
  error_summary: errorsData,
};

return [{ json: result }];
